```C [sol1-C]
typedef struct {
    int key;
    UT_hash_handle hh;
} HashItem; 

HashItem *hashFindItem(HashItem **obj, int key) {
    HashItem *pEntry = NULL;
    HASH_FIND_INT(*obj, &key, pEntry);
    return pEntry;
}

bool hashAddItem(HashItem **obj, int key) {
    if (hashFindItem(obj, key)) {
        return false;
    }
    HashItem *pEntry = (HashItem *)malloc(sizeof(HashItem));
    pEntry->key = key;
    HASH_ADD_INT(*obj, key, pEntry);
    return true;
}

void hashFree(HashItem **obj) {
    HashItem *curr = NULL, *tmp = NULL;
    HASH_ITER(hh, *obj, curr, tmp) {
        HASH_DEL(*obj, curr);  
        free(curr);
    }
}

int same(int* nums1, int nums1Size, int* nums2, int nums2Size) {
    HashItem *set = NULL;
    for (int i = 0; i < nums1Size; i++) {
        hashAddItem(&set, nums1[i]);
    }
    int x = 10;
    for (int i = 0; i < nums2Size; i++) {
        if (hashFindItem(&set, nums2[i])) {
            x = fmin(x, nums2[i]);
        }
    }
    hashFree(&set);
    return x == 10 ? -1 : x;
}

int minNumber(int* nums1, int nums1Size, int* nums2, int nums2Size) {
    int count = same(nums1, nums1Size, nums2, nums2Size);
    if (count != -1) {
        return count;
    }
    int x = INT_MAX, y = INT_MAX;
    for (int i = 0; i < nums1Size; i++) {
        x = fmin(x, nums1[i]);
    }
    for (int i = 0; i < nums2Size; i++) {
        y = fmin(y, nums2[i]);
    }
    return fmin(x * 10 + y, y * 10 + x);
}       
```

```Go [sol1-Go]
func minNumber(nums1 []int, nums2 []int) int {
    var same = func() int {
        s := make(map[int]bool)
        x := 10
        for _, num := range nums1 {
            s[num] = true
        }
        for _, num := range nums2 {
            if _, ok := s[num]; ok {
                x = min(x, num)
            }
        }
        if x == 10 {
            return -1
        }
        return x
    }

    if x := same(); x != -1 {
        return x;
    }
    x, y := nums1[0], nums2[0]
    for _, num := range nums1 {
        x = min(x, num)
    }
    for _, num := range nums2 {
        y = min(y, num)
    }
    return min(x * 10 + y, y * 10 + x)
}

func min(x int, y int) int {
    if x > y {
        return y
    }
    return x
}
```

```JavaScript [sol1-JavaScript]
var minNumber = function(nums1, nums2) {
    const same = () => {
        const s = new Set(nums1);
        let x = 10;
        for (const m of nums2) {
            if (s.has(m)) {
                x = Math.min(x, m);
            }
        }
        return x == 10 ? -1 : x;
    }
    const count = same();
    if (count != -1) {
        return count;
    }
    const x = Math.min(...nums1);
    const y = Math.min(...nums2);
    return Math.min(x * 10 + y, y * 10 + x);
};
```

**复杂度分析**

- 时间复杂度：$O(m + n)$，其中 $m$ 和 $n$ 分别是数组 $\textit{nums}_1$ 和 $\textit{nums}_2$ 的长度。

- 空间复杂度：$O(m)$，即为哈希表需要使用的空间。
